import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactElement } from 'react';
import type { TabbarType } from '../Tabbar.types';
/**
 * Пропсы элемента нижней панели навигации (TabbarItem).
 * Элемент может работать как кнопка (через onClick) или как ссылка (через routingComponent).
 */
export interface TabbarItemProps {
    /**
     * Дополнительный CSS-класс для элемента.
     */
    className?: string;
    /**
     * Имя иконки из дизайн-токенов.
     * Иконка обязательна и является основным ориентиром для пункта.
     */
    iconName: Icons;
    /**
     * Подпись пункта. Отображается только в `type="default"`.
     */
    label?: string;
    /**
     * Активное состояние пункта (текущий раздел).
     * Визуально подсвечивает элемент.
     */
    active?: boolean;
    /**
     * Блокировка пункта. При `true` пункт не кликабелен и не фокусируется.
     */
    disabled?: boolean;
    /**
     * Вариант отображения, пробрасывается из `Tabbar`.
     * Не задавайте напрямую, если пункт отрисовывается внутри `Tabbar`.
     */
    type?: TabbarType;
    /**
     * Обработчик клика по пункту.
     * При наличии обработчика элемент получает `role="button"` и поддержку клавиш `Enter`/`Space`.
     */
    onClick?: (event: React.MouseEvent) => void;
    /**
     * Обёртка для интеграции с роутером (например, `<Link to="/...">`).
     * Если передана, пункт будет отрендерен внутри этого компонента.
     */
    routingComponent?: ReactElement<unknown>;
}
